class DataService {
  cache = new Map();
  async fetchAll(ids) {
    const results = await Promise.all(
      ids.map(function(id) {
        if (this.cache.has(id)) {
          return this.cache.get(id);
        }
        return fetch(`/api/${id}`);
      })
    );
    return results;
  }
}
